// Wall clock face — circular dial, 12 hour markers (longer at cardinals),
// 60 minute ticks, hour + minute + red second hand posed at 10:10, central hub.
const { Manifold, CrossSection, label } = api;

// --- Parameters (mm-ish, units arbitrary) ---
const dialR     = 50;    // 100 mm diameter
const dialH     = 4;     // dial thickness
const dialTop   = dialH; // z = 4 sits on top of dial
const sink      = 0.6;

// Bezel/rim: an outer ring proud of the dial face.
const rimInnerR = 45;    // dial face shows inside this radius
const rimH      = 1.6;   // rim stands proud of the dial top

// Hour markers: short rectangular pegs near the rim.
const hourW = 2.6, hourL = 7,  hourH = 1.2;
const hourR = 42;
const cardW = 3.4, cardL = 11, cardH = 1.4;
const cardR = 40;

// Minute ticks: thin slivers between hour markers.
const tickW = 0.9, tickL = 3, tickH = 0.8;
const tickR = 46;

// Hands.
const hourHandL = 28, hourHandW = 3.0, hourHandT = 1.2;
const minHandL  = 40, minHandW  = 2.2, minHandT  = 1.2;
const secHandL  = 44, secHandW  = 1.0, secHandT  = 1.0;

// Central hub.
const pinR = 2.4, pinH = 3.5;

// --- Dial: a low cylinder centered at origin ---
const dialFull = Manifold.cylinder(dialH, dialR, dialR);

// Split the dial face into an inner disc (white) and an outer bezel ring.
// The dial disc is the full base cylinder up to dialH — it owns the visible
// inner face. The bezel is a true RING that rises proud of that face, so the
// two labels each own a distinct, un-consumed surface after the union.
//
// Inner dial disc (white/cream face): the full-radius base. Its top at z=dialH
// is the flat face that markers/hands sit on, and stays the visible inner top.
const dialDisc = label(
  Manifold.cylinder(dialH, dialR, dialR),
  'dial'
);

// Bezel = a brass ring (annulus) standing proud of the dial face. It spans
// the rim band [rimInnerR .. dialR] and rises from z=0 up to dialH+rimH, so it
// frames the dial without covering the inner face the dial disc provides.
const rimOuter = Manifold.cylinder(dialH + rimH, dialR, dialR);
const rimInnerBore = Manifold.cylinder(dialH + rimH + 2, rimInnerR, rimInnerR)
  .translate([0, 0, -1]);
const bezel = label(rimOuter.subtract(rimInnerBore), 'bezel');

// --- Hour markers ---
const hourMarker = Manifold.cube([hourW, hourL, hourH], true)
  .translate([0, 0, dialTop + hourH / 2 - sink]);
const hourMarkers = label(api.circularPattern(hourMarker, 12, { radius: hourR }), 'markers');

// --- Cardinal markers (longer/thicker, at 12 / 3 / 6 / 9) ---
const cardMarker = Manifold.cube([cardW, cardL, cardH], true)
  .translate([0, 0, dialTop + cardH / 2 - sink]);
const cardMarkers = label(api.circularPattern(cardMarker, 4, { radius: cardR }), 'markers');

// --- Minute ticks ---
const tick = Manifold.cube([tickW, tickL, tickH], true)
  .translate([0, 0, dialTop + tickH / 2 - sink]);
const ticks = label(api.circularPattern(tick, 60, { radius: tickR }), 'markers');

// --- Hands, posed for the classic 10:10 watch-ad pose ---
function makeHand(length, width, thickness) {
  const root = Manifold.cube([width,        width, thickness], true)
    .translate([0, width / 2, thickness / 2]);
  const tip = Manifold.cube([width * 0.45,  width, thickness], true)
    .translate([0, length - width / 2, thickness / 2]);
  return Manifold.hull([root, tip]);
}

const hourHand = label(
  makeHand(hourHandL, hourHandW, hourHandT)
    .translate([0, 0, dialTop - sink])
    .rotate([0, 0, 60]),
  'hands');
const minuteHand = label(
  makeHand(minHandL, minHandW, minHandT)
    .translate([0, 0, dialTop - sink])
    .rotate([0, 0, -60]),
  'hands');

// Red second hand — a thin sliver, pointing toward "30 seconds" (numeral 6, -Y),
// slightly above the other hands so it reads on top.
const secondHand = label(
  makeHand(secHandL, secHandW, secHandT)
    .translate([0, 0, dialTop - sink + 0.2])
    .rotate([0, 0, 180]),
  'secondHand');

// --- Central hub: hides where the hands cross. ---
let pin = Manifold.cylinder(pinH, pinR, pinR * 0.85);
pin = label(
  api.alignTo(pin, dialFull, { x: 'center', y: 'center' })
    .translate([0, 0, dialTop - sink]),
  'hub');

// --- Final assembly + sanity check ---
const clock = api.expectUnion(
  [bezel, dialDisc, hourMarkers, cardMarkers, ticks, hourHand, minuteHand, secondHand, pin],
  { expectComponents: 1 },
);

return clock;

